from __future__ import annotations

from dataclasses import dataclass
from typing import Dict, List, Sequence, Tuple


class AllocationPhase3SuiteRunnerError(RuntimeError):
    """Raised when the named allocation Phase 3 suite is malformed."""


ALLOCATION_PHASE3_PATCH_RANGE: Tuple[int, int] = (164, 170)

ALLOCATION_PHASE3_TEST_MODULES: Tuple[str, ...] = (
    "tests.test_chain_strategy_budget_policy",
    "tests.test_allocation_candidate",
    "tests.test_allocation_decision",
    "tests.test_allocation_decision_store",
    "tests.test_final_portfolio_constraint_gate",
    "tests.test_allocation_review_packet_builder",
    "tests.test_allocation_replay_report",
)


@dataclass(frozen=True)
class AllocationPhase3SuiteDefinition:
    suite_name: str
    patch_range_start: int
    patch_range_end: int
    test_modules: Tuple[str, ...]
    notes: str

    def to_dict(self) -> Dict[str, object]:
        return {
            "suite_name": self.suite_name,
            "patch_range_start": self.patch_range_start,
            "patch_range_end": self.patch_range_end,
            "test_modules": list(self.test_modules),
            "notes": self.notes,
        }


def build_allocation_phase3_suite_definition() -> AllocationPhase3SuiteDefinition:
    return AllocationPhase3SuiteDefinition(
        suite_name="allocation_phase3_suite",
        patch_range_start=ALLOCATION_PHASE3_PATCH_RANGE[0],
        patch_range_end=ALLOCATION_PHASE3_PATCH_RANGE[1],
        test_modules=ALLOCATION_PHASE3_TEST_MODULES,
        notes=(
            "Named allocator Phase 3 suite covering budget policy, allocation "
            "candidate/decision flow, persistence, final constraint gate, review "
            "packet rendering, and replay audit."
        ),
    )


def validate_allocation_phase3_suite(
    test_modules: Sequence[str] | None = None,
) -> Tuple[str, ...]:
    modules = tuple(ALLOCATION_PHASE3_TEST_MODULES if test_modules is None else test_modules)
    if not modules:
        raise AllocationPhase3SuiteRunnerError("allocation phase 3 suite must not be empty")

    normalized: List[str] = []
    for module_name in modules:
        if not isinstance(module_name, str) or not module_name.strip():
            raise AllocationPhase3SuiteRunnerError(
                "allocation phase 3 suite modules must be non-empty strings"
            )
        normalized_name = module_name.strip()
        if normalized_name in normalized:
            raise AllocationPhase3SuiteRunnerError(
                f"duplicate allocation phase 3 suite module: {normalized_name}"
            )
        normalized.append(normalized_name)

    return tuple(normalized)


def build_allocation_phase3_suite_args() -> List[str]:
    modules = validate_allocation_phase3_suite()
    return ["-m", "unittest", "-v", *modules]


def build_allocation_phase3_suite_command(python_program: str = "python") -> List[str]:
    if not isinstance(python_program, str) or not python_program.strip():
        raise AllocationPhase3SuiteRunnerError("python_program must be a non-empty string")
    return [python_program.strip(), *build_allocation_phase3_suite_args()]


def build_allocation_phase3_suite_metadata() -> Dict[str, object]:
    definition = build_allocation_phase3_suite_definition()
    modules = validate_allocation_phase3_suite(definition.test_modules)
    return {
        **definition.to_dict(),
        "validated_module_count": len(modules),
        "command_args": build_allocation_phase3_suite_args(),
    }
